// Function to read the file and update the DOM
function updateHtmlFromJava() {
    // Fetch the text file generated by your Java program
    fetch('data.txt')
        .then(response => {
            if (!response.ok) {
                throw new Error('Could not find data.txt file');
            }
            return response.text(); // Read the content as a string
        })
        .then(javaString => {
            // Find the HTML element and update its text
            document.getElementById('output-text').textContent = javaString;
        })
        .catch(error => {
            console.error('Error fetching Java data:', error);
            document.getElementById('output-text').textContent = 'Error loading data.';
        });
}

// Run the function when the page loads
window.onload = updateHtmlFromJava;
